import warning from '@andes/common/build/utils/warning';
import { WARNING_DEPRECATED_MODIFIER_WARNING } from '../constants/warnings/shared';

/** @typedef {import('../..').TextFieldProps["modifier"] | "caution"} ModifierProp */

const DEPRECATED_MODIFIERS = ['warning'];

/** @param {ModifierProp} [modifier] */
export const computeModifier = (modifier) => {
  warning(!modifier || (typeof modifier === 'string' && !DEPRECATED_MODIFIERS.includes(modifier)), WARNING_DEPRECATED_MODIFIER_WARNING);

  switch (modifier) {
    case 'warning':
    case 'caution':
      return 'caution';
    case 'error':
      return 'error';
    default:
      return undefined;
  }
};
