import PropTypes from 'prop-types';
import includes from '@andes/common/build/utils/includes';

const WARNING_LABEL = `Some plain text contents are needed for accessibility reasons.
Please add a \`label\` or \`srLabel\` prop.`;
const WARNING_CHILDREN_NOT_SUPPORTED = `This child is not supported, use instead a text, 'tooltip', 'clear icon' 
or other component as recommended by the documentation.`;
const WARNING_DEPRECATED_MODIFIER_WARNING = `\`warning\` modifier will be deprecated in a future major version.
Please use \`caution\` instead.`;

/** @type {import('prop-types').Validator<string>} */
const checkLabelProp = ({ label, srLabel }, propName, componentName) => {
  PropTypes.checkPropTypes({ label: PropTypes.string }, { label }, propName, componentName);
  PropTypes.checkPropTypes({ srLabel: PropTypes.string }, { label }, propName, componentName);

  return !label && !srLabel ? new Error(WARNING_LABEL) : null;
};

/** @type {import('prop-types').Validator<PropTypes.node>} */
const checkChildrenProp = ({ children }, propName, componentName) => {
  PropTypes.checkPropTypes({ children: PropTypes.node }, { children }, propName, componentName);
  return includes(['Button', 'Checkbox'], children?.type?.displayName)
    ? new Error(WARNING_CHILDREN_NOT_SUPPORTED) : null;
};

export {
  checkLabelProp,
  checkChildrenProp,
  WARNING_DEPRECATED_MODIFIER_WARNING,
};
