/* eslint-disable react/sort-comp, max-len */
import React from 'react';
import PropTypes from 'prop-types';
import { i18NPropTypeChecker } from '@andes/common/build/utils/propTypesValidators';
import classNames from 'classnames';
import { FocusRing } from '@react-aria/focus';
import { VisuallyHidden } from '@andes/visually-hidden';
import { autofocus as inputAutoFocus } from '@andes/common/build/utils/autofocus';
import { ProgressIndicatorCircular } from '@andes/progress-indicator-circular';
import autosize from 'autosize';
import ValidatedIcon from './ValidatedIcon';
import ClearButton from './ClearButton';
import { checkLabelProp } from '../constants/warnings/shared';
import { formControlNamespace, namespace } from '../constants';
import { Helper } from '@andes/form';
import { computeModifier } from '../utils';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';

/**
 * @typedef TextFieldState
 * @prop {string} height
 * @prop {number} countdown
 * @prop {boolean} focused
 * @prop {HTMLInputElement | HTMLTextAreaElement | null} fieldRef
 * @prop {TextFieldProps} prevProps
 */

/**
 * @typedef {Object} TextFieldInternalProps
 * @prop {React.RefObject<HTMLDivElement | null> | ((refElement: HTMLDivElement | null) => void)} [innerRef]
 * @prop {boolean} [embeddedChildren]
 * @prop {import('@meli/i18n').I18n} i18n
 * @prop {boolean} [numeric]
 * @prop {boolean} [split]
 * @prop {Record<string, unknown>} [andesDataAttributes]
 */

/** @typedef {import('../..').TextFieldProps} TextFieldPublicProps */
/** @typedef {TextFieldPublicProps & TextFieldInternalProps} TextFieldProps */

const emptyEvent = /** @type {React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>} */({ target: { value: '' } });

/**
 * Textfield allows enter data. It can be for enter numbers, text and passwords as well.
 */

/** @extends {React.Component<TextFieldProps, TextFieldState>} */
class TextField extends React.Component {
  /** @param {TextFieldProps} props */
  constructor(props) {
    super(props);

    const value = String(props.defaultValue || props.value || '');

    /** @type TextFieldState */
    this.state = {
      height: 'auto',
      fieldRef: null,
      countdown: value.length,
      focused: props.autoFocus || false,
      prevProps: props,
    };

    this.isUncontrolledValue = props.value === undefined;

    this.setField = this.setField.bind(this);
    this.setRef = this.setRef.bind(this);
    this.onBlurHandler = this.onBlurHandler.bind(this);
    this.onFocusHandler = this.onFocusHandler.bind(this);
    this.onInputHandler = this.onInputHandler.bind(this);
    this.onChangeHandler = this.onChangeHandler.bind(this);
    this.onClearHandler = this.onClearHandler.bind(this);
  }

  componentDidMount() {
    const { multiline = false, focus = false, select = false, autoFocus = false } = this.props;
    const { field } = this;

    if (multiline && field) autosize(field);

    if (focus || autoFocus) {
      inputAutoFocus(field);
    }

    if (select) field?.select();
  }

  /**
   * @param {TextFieldState} prevState
   * @param {TextFieldProps} nextProps
   */
  static getDerivedStateFromProps(nextProps, prevState) {
    const { fieldRef, prevProps } = prevState;
    const { multiline = false, value: nextValue, focus = false, select = false, countdown = false } = nextProps;
    // @ts-expect-error
    const { isUncontrolledValue } = prevState;

    const propsToCheck = ['multiline', 'focus', 'select', 'value', 'countdown'];

    const changedProps = propsToCheck.some((prop) => nextProps[prop] !== prevProps[prop]);

    if (changedProps) {
      if (multiline && fieldRef) autosize.update(fieldRef);

      if (focus) fieldRef?.focus();

      if (select) fieldRef?.select();

      // Count characters
      if (countdown && !isUncontrolledValue && nextValue !== fieldRef?.value) {
        return { countdown: String(nextValue).length, prevProps: nextProps };
      }
    }

    return changedProps ? { prevProps: nextProps } : null;
  }

  /** @param {React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>} event */
  onBlurHandler(event) {
    const { onBlur } = this.props;

    this.setState({ focused: false });
    if (onBlur) onBlur(event);
  }

  /** @param {React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>} event */
  onFocusHandler(event) {
    const { onFocus } = this.props;

    this.setState({ focused: true });
    if (onFocus) onFocus(event);
  }

  /** @param {React.FormEvent<HTMLInputElement | HTMLTextAreaElement>} event */
  onInputHandler(event) {
    const { onInput } = this.props;
    const { target: { value } } = /** @type {React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>} */(event);

    this.setState({ countdown: value.length });

    if (typeof onInput === 'function') onInput(/** @type {React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>} */(event));
  }

  /** @param {React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>} event */
  onChangeHandler(event) {
    const { onChange } = this.props;

    if (typeof onChange === 'function') onChange(event);
  }

  onClearHandler() {
    const { onChange } = this.props;
    const { field, isUncontrolledValue, onInputHandler, onChangeHandler } = this;

    if (isUncontrolledValue) /** @type {HTMLInputElement | HTMLTextAreaElement} */(field).value = '';
    onInputHandler(emptyEvent);
    if (onChange) onChangeHandler(emptyEvent);
  }

  /** @param {HTMLInputElement | HTMLTextAreaElement | null} field */
  setField(field) {
    this.field = field;
    this.setState({ fieldRef: field });
  }

  /** @param {HTMLDivElement} ref */
  setRef(ref) {
    const { innerRef } = this.props;

    if (typeof innerRef === 'function') {
      innerRef(ref);
      return;
    }
    if (innerRef) innerRef.current = ref;
  }

  renderChildren() {
    const { children, embeddedChildren = true } = this.props;
    if (embeddedChildren) {
      return (
        <div
          className={`${formControlNamespace}__embedded`}
          data-andes-textfield-right-content
        >
          {children}
        </div>
      );
    }

    return children;
  }

  renderHelper() {
    const { helper, id, modifier } = this.props;

    return (
      <>
        {helper
          && (
            <Helper
              id={`${id}-message`}
              modifier={computeModifier(modifier)}
              className={`${formControlNamespace}--internal-helper`}
              // @ts-expect-error: Internal prop
              andesDataAttributes={{ 'data-andes-textfield-helper': true }}
            >
              {helper}
            </Helper>
          )}
      </>
    );
  }

  render() {
    const {
      centered = false,
      children,
      className,
      clear = false,
      countdown = false,
      disabled = false,
      defaultValue,
      embeddedChildren,
      focus,
      helper,
      id,
      innerRef,
      i18n,
      inputProps = {},
      label,
      maxLength = 120,
      modifier,
      multiline = false,
      numeric = false,
      onChange,
      placeholder,
      prefix = '',
      rows = 1,
      select,
      size = 'large',
      split = false,
      srLabel,
      suffix = '',
      value,
      autoFocus,
      andesDataAttributes,
      ...otherProps
    } = this.props;

    const { focused, height, countdown: count } = this.state;

    const showBottomInfo = !numeric && !split && modifier !== 'readonly' && !disabled && (countdown || helper);

    const classes = classNames(formControlNamespace, `${formControlNamespace}--textfield`, className, {
      [`${formControlNamespace}--multiline`]: multiline,
      [`${formControlNamespace}--countdown`]: countdown,
      [`${formControlNamespace}--centered`]: centered,
      [`${formControlNamespace}--focused`]: focused,
      [`${formControlNamespace}--${modifier}`]: modifier,
      [`${formControlNamespace}--disabled`]: disabled,
      [`${formControlNamespace}--medium`]: size === 'medium',
      [`${formControlNamespace}--textfield-with-prefix`]: !!prefix,
      [`${formControlNamespace}--textfield-with-suffix`]: !!suffix,
    });

    const getAriaDescribedby = () => {
      const { 'aria-describedby': ariaDescribedby } = inputProps;
      if (split) return ariaDescribedby;

      if (helper && countdown) return `${id}-message ${id}-count`;
      if (countdown) return `${id}-count`;
      if (helper) return `${id}-message`;
    };

    const suffixClasses = classNames(`${formControlNamespace}__suffix`);

    const prefixClasses = classNames(`${formControlNamespace}__prefix`);

    const fieldClasses = classNames(`${formControlNamespace}__field`, {
      [`${formControlNamespace}__field--multiline`]: multiline,
      [`${formControlNamespace}--medium`]: size === 'medium',
    });

    const bottomInfoClasses = classNames(`${formControlNamespace}__bottom`, {
      [`${formControlNamespace}--medium`]: size === 'medium',
    });

    const fieldProps = {
      ...otherProps,
      ...inputProps,
      id,
      defaultValue,
      value,
      className: fieldClasses,
      disabled: disabled || modifier === 'readonly',
      // eslint-disable-next-line object-shorthand
      maxLength: /** @type {number} */(maxLength),
      style: multiline ? { height } : {},
      placeholder,
      onBlur: this.onBlurHandler,
      onFocus: this.onFocusHandler,
      onChange: this.onChangeHandler,
      ref: this.setField,
      'aria-invalid': modifier === 'error' || modifier === 'warning' || modifier === 'caution' || inputProps?.['aria-invalid'] || /** @type {boolean} */(otherProps['aria-invalid']),
      'aria-label': srLabel,
      'aria-describedby': getAriaDescribedby(),
      // eslint-disable-next-line object-shorthand
      rows: /** @type {number} */(rows),
      autoFocus: focus || autoFocus,
    };

    const Input = multiline ? 'textarea' : 'input';

    return (
      <div
        className={classes}
        ref={this.setRef}
        {...andesDataAttributes}
        data-andes-textfield
        data-andes-textfield-modifier={modifier}
        {...computeDataAndesState({ disabled, error: modifier === 'error', warning: modifier === 'warning' })}
      >
        {label && <label htmlFor={id} data-andes-textfield-label><span className={`${formControlNamespace}__label`}>{label}</span></label>}
        <FocusRing within isTextInput focusRingClass={focused ? 'visible-focused' : ''}>
          <div className={`${formControlNamespace}__control`}>
            {prefix && <span className={prefixClasses} data-andes-textfield-prefix>{prefix}</span>}

            {/* @ts-expect-error inputProps could have attributes from textarea or input  */}
            <Input key="field" {...fieldProps} onInput={this.onInputHandler} data-andes-textfield-input data-andes-textfield-input-type={Input} />

            {suffix && <span className={suffixClasses} data-andes-textfield-suffix>{suffix}</span>}

            {modifier === 'completed' && (
            <ValidatedIcon
              notificationsLabel={i18n.pgettext(namespace, 'Campo de texto valido')}
              size={size}
            />
            )}

            {modifier === 'indeterminate' && (
            <ProgressIndicatorCircular
              className={`${formControlNamespace}--textfield-progress`}
              size="xsmall"
              srAnnouncement={i18n.pgettext(namespace, 'Campo de texto procesando')}
              srLabel={i18n.pgettext(namespace, 'Campo de texto procesando')}
            />
            )}

            {clear && (
            <ClearButton
              aria-label={i18n.pgettext(namespace, 'Borrar')}
              namespace={formControlNamespace}
              onClick={this.onClearHandler}
              size={size}
            />
            )}

            {children && this.renderChildren()}
          </div>
        </FocusRing>

        {showBottomInfo && (
        <div className={bottomInfoClasses} data-andes-textfield-bottom-info>
          {this.renderHelper()}
          {countdown && (
          <>
            <span
              id={`${id}-countdown-progress`}
              className={`${formControlNamespace}__countdown`}
              role="progressbar"
              aria-valuenow={count}
              aria-valuemin={0}
              aria-valuemax={Number(maxLength)}
              aria-label={i18n.pgettext(namespace, 'Maximo {0} caracteres', maxLength)}
              data-andes-textfield-countdown
            >
              {`${count} / ${maxLength}`}
            </span>
            <VisuallyHidden id={`${id}-count`} aria-live="polite" aria-atomic="true">
              {i18n.pgettext(namespace, '{0} caracteres restantes', Number(maxLength) - count)}
            </VisuallyHidden>
          </>
          )}
        </div>
        )}
      </div>
    );
  }
}

TextField.displayName = 'TextField';

TextField.propTypes = {
  andesDataAttributes: PropTypes.shape({}),
  autoFocus: PropTypes.bool,
  centered: PropTypes.bool,
  children: PropTypes.node,
  className: PropTypes.string,
  clear: PropTypes.bool,
  countdown: PropTypes.bool,
  defaultValue: PropTypes.string,
  disabled: PropTypes.bool,
  embeddedChildren: PropTypes.bool,
  focus: PropTypes.bool,
  helper: PropTypes.oneOfType([PropTypes.string, PropTypes.node]),
  id: PropTypes.string.isRequired,
  innerRef: PropTypes.oneOfType([
    PropTypes.func,
    PropTypes.shape({ current: PropTypes.oneOfType([PropTypes.node, PropTypes.object]) }),
  ]),
  inputProps: PropTypes.shape({}),
  i18n: i18NPropTypeChecker,
  label: checkLabelProp,
  maxLength: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  modifier: PropTypes.oneOf(['indeterminate', 'completed', 'error', 'readonly', 'caution']),
  multiline: PropTypes.bool,
  numeric: PropTypes.bool,
  onBlur: PropTypes.func,
  onChange: PropTypes.func,
  onFocus: PropTypes.func,
  onInput: PropTypes.func,
  placeholder: PropTypes.string,
  prefix: PropTypes.string,
  rows: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  select: PropTypes.bool,
  size: PropTypes.oneOf(['medium', 'large']),
  split: PropTypes.bool,
  srLabel: checkLabelProp,
  suffix: PropTypes.string,
  value: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
};

export default TextField;
