import React from 'react';
import classNames from 'classnames';
import Numeric from './Numeric';
import PropTypes from 'prop-types';
import { checkLabelProp } from '../constants/warnings/shared';
import { useId } from '@andes/context';
import { useThemeContext } from '@andes/themes';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';

const namespace = 'andes-code-input';

/**
 * @typedef {import('../..').CodeInput} CodeInputProps
 */

/** @type {CodeInputProps} */
const CodeInput = ({
  className,
  id,
  ref,
  ...otherProps
}) => {
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  const codeInputClassNames = classNames(namespace, className, getThemedComponentClasses?.('textfield'));
  const componentId = useId(id);
  const { disabled, modifier } = otherProps;

  return (
    <Numeric
      className={codeInputClassNames}
      id={componentId}
      ref={ref}
      andesDataAttributes={{ 'data-andes-codeinput': true, 'data-andes-codeinput-modifier': modifier, ...computeDataAndesState({ disabled, error: modifier === 'error' }), ...themeHash }}
      {...otherProps}
    />
  );
};

CodeInput.displayName = 'CodeInput';

CodeInput.propTypes = {
  centered: PropTypes.bool,
  className: PropTypes.string,
  defaultValue: PropTypes.oneOfType([
    PropTypes.arrayOf(PropTypes.string),
    PropTypes.string,
  ]),
  digits: PropTypes.number,
  disabled: PropTypes.bool,
  focus: PropTypes.oneOfType([PropTypes.bool, PropTypes.number]),
  helper: PropTypes.oneOfType([PropTypes.string, PropTypes.node]),
  id: PropTypes.string,
  label: checkLabelProp,
  modifier: PropTypes.oneOf(['completed', 'error']),
  onChange: PropTypes.func,
  onPaste: PropTypes.func,
  strict: PropTypes.bool,
  srLabel: checkLabelProp,
  value: PropTypes.oneOfType([
    PropTypes.arrayOf(PropTypes.string),
    PropTypes.string,
  ]),
};

export default CodeInput;
